#include<bits/stdc++.h>
using namespace std;
struct n{int a,b;}t[5005];
bool cmp(n x,n y){return x.a<y.a;}
int main(void){
    int n,m,i,sum=0;
    std::cin>>n>>m;
    for(i=0;i<m;i++)std::cin>>t[i].a>>t[i].b; 
    sort(t,t+m,cmp);i=0;
    while(true){
        if(n>t[i].b){sum+=t[i].a*t[i].b;n-=t[i].b;}
		else{sum+=n*t[i].a;break;}i++;
    }std::cout<<sum;
    return false;
}
